  244: 		rb_erase(&re->node, &be->roots);
  245: 		kfree(re);
  246: 	}
  247: 
  248: 	while((n = rb_first(&be->refs))) {
  249: 		ref = rb_entry(n, struct ref_entry, node);
  250: 		rb_erase(&ref->node, &be->refs);
