 1154: 
 1155: 		btrfs_info_in_rcu(fs_info,
 1156: 		"suspended dev_replace from %s (devid %llu) to %s canceled",
 1157: 			btrfs_dev_name(src_device), src_device->devid,
 1158: 			btrfs_dev_name(tgt_device));
 1159: 
 1160: 		if (tgt_device)
 1161: 			btrfs_destroy_dev_replace_tgtdev(tgt_device);
 1162: 		break;
 1163: 	default:
 1164: 		up_write(&dev_replace->rwsem);
 1165: 		result = -EINVAL;
 1166: 	}
 1167: 
 1168: 	mutex_unlock(&dev_replace->lock_finishing_cancel_unmount);
 1169: 	return result;
 1170: }
