 1172: void btrfs_dev_replace_suspend_for_unmount(struct btrfs_fs_info *fs_info)
 1173: {
 1174: 	struct btrfs_dev_replace *dev_replace = &fs_info->dev_replace;
 1175: 
 1176: 	mutex_lock(&dev_replace->lock_finishing_cancel_unmount);
 1177: 	down_write(&dev_replace->rwsem);
 1178: 
 1179: 	switch (dev_replace->replace_state) {
 1180: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_NEVER_STARTED:
 1181: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_FINISHED:
 1182: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_CANCELED:
 1183: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_SUSPENDED:
 1184: 		break;
 1185: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_STARTED:
 1186: 		dev_replace->replace_state =
 1187: 			BTRFS_IOCTL_DEV_REPLACE_STATE_SUSPENDED;
 1188: 		dev_replace->time_stopped = ktime_get_real_seconds();
 1189: 		dev_replace->item_needs_writeback = 1;
 1190: 		btrfs_info(fs_info, "suspending dev_replace for unmount");
 1191: 		break;
 1192: 	}
 1193: 
 1194: 	up_write(&dev_replace->rwsem);
 1195: 	mutex_unlock(&dev_replace->lock_finishing_cancel_unmount);
 1196: }
